local ADDON_NAME, ns = ...
if GetLocale() ~= "ptBR" then return end
local L = ns.L

L["%s only"] = "Apenas %s"
L["0 (professions only)"] = "0 (apenas profissões)"
L["About"] = "Sobre"
L["Adds this profession's recipes an item is used in to its tooltip, with the skill range that still gives points and whether you know the recipe."] = "Adiciona à dica de um item as receitas desta profissão em que ele é usado, com a faixa de habilidade que ainda dá pontos e se você conhece a receita."
L["Also annotates reagents of professions this character does not have (as if at skill 0) - useful to decide what to keep or send to alts."] = "Anota também os reagentes de profissões que este personagem não tem (como se estivesse com habilidade 0) - útil para decidir o que guardar ou enviar para os alts."
L["Always show"] = "Sempre mostrar"
L["Author: %s"] = "Autor: %s"
L["Could not open the settings window on this client. Find the options under Game Menu -> Options -> AddOns -> ProfessionTips."] = "Não foi possível abrir a janela de configurações neste cliente. As opções estão em Menu do Jogo -> Opções -> AddOns -> ProfessionTips."
L["Display"] = "Exibição"
L["Include processed materials"] = "Incluir materiais processados"
L["List only recipes this character has already learned. Unlearned recipes still count for the header's accumulated skill range and the '+N more' summary."] = "Listar apenas as receitas que este personagem já aprendeu. Receitas não aprendidas ainda contam para a faixa de habilidade do cabeçalho e o resumo '+N mais'."
L["more recipes give points"] = "outras receitas dão pontos"
L["no skillups"] = "não dá mais pontos"
L["not learned"] = "não aprendida"
L["Only add the tooltip information while this modifier key is held down."] = "Adicionar as informações à dica apenas enquanto esta tecla modificadora estiver pressionada."
L["Only learned recipes"] = "Apenas receitas aprendidas"
L["processed material"] = "material processado"
L["Professions"] = "Profissões"
L["Raw materials also show the recipes of what they are processed into (cloth into bolts, ore into bars, hides into cured hides, ...), marked with 'via'."] = "Matérias-primas também mostram as receitas daquilo em que são transformadas (tecido em rolos, minério em barras, peles em peles curtidas, ...), marcadas com 'via'."
L["Recipe lines per profession section. 0 shows only the profession headers with their accumulated skill range; otherwise at least 2 (the lowest- and highest-requirement recipes always appear together). More recipes are summarized as '+N more'."] = "Linhas de receitas por seção de profissão. 0 mostra apenas os cabeçalhos de profissão com sua faixa de habilidade acumulada; caso contrário, no mínimo 2 (as receitas de requisito mais baixo e mais alto sempre aparecem juntas). Receitas adicionais são resumidas como '+N mais'."
L["Recipes listed per profession"] = "Receitas listadas por profissão"
L["Show for missing professions"] = "Mostrar para profissões que você não tem"
L["Show only while holding"] = "Mostrar apenas ao segurar"
L["Version: %s"] = "Versão: %s"
L["via %s"] = "via %s"
